import{_ as s,o as e,c as i,aS as t}from"./chunks/framework.DdSiWJCR.js";const b=JSON.parse('{"title":"GitHub Pages 部署指南","description":"","frontmatter":{},"headers":[],"relativePath":"使用指南/GitHub-Pages部署指南.md","filePath":"使用指南/GitHub-Pages部署指南.md","lastUpdated":null}'),n={name:"使用指南/GitHub-Pages部署指南.md"};function l(r,a,o,h,d,p){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="github-pages-部署指南" tabindex="-1">GitHub Pages 部署指南 <a class="header-anchor" href="#github-pages-部署指南" aria-label="Permalink to &quot;GitHub Pages 部署指南&quot;">​</a></h1><h2 id="访问地址-启用后" tabindex="-1">访问地址（启用后） <a class="header-anchor" href="#访问地址-启用后" aria-label="Permalink to &quot;访问地址（启用后）&quot;">​</a></h2><p><a href="https://xiaobawang001.github.io/" target="_blank" rel="noreferrer">https://xiaobawang001.github.io/</a></p><hr><h2 id="前置条件-仓库命名" tabindex="-1">前置条件：仓库命名 <a class="header-anchor" href="#前置条件-仓库命名" aria-label="Permalink to &quot;前置条件：仓库命名&quot;">​</a></h2><p>仓库名必须为 <code>xiaobawang001.github.io</code>，GitHub Pages 才会在根路径提供服务。如果仓库还叫 <code>blog</code>，先去 GitHub 重命名。</p><h2 id="首次启用-必做-只需一次" tabindex="-1">首次启用（必做，只需一次） <a class="header-anchor" href="#首次启用-必做-只需一次" aria-label="Permalink to &quot;首次启用（必做，只需一次）&quot;">​</a></h2><h3 id="第-1-步-把-source-设为-github-actions" tabindex="-1">第 1 步：把 Source 设为 GitHub Actions <a class="header-anchor" href="#第-1-步-把-source-设为-github-actions" aria-label="Permalink to &quot;第 1 步：把 Source 设为 GitHub Actions&quot;">​</a></h3><ol><li>打开 <a href="https://github.com/xiaobawang001/xiaobawang001.github.io/settings/pages" target="_blank" rel="noreferrer">https://github.com/xiaobawang001/xiaobawang001.github.io/settings/pages</a></li><li>在 <strong>Build and deployment</strong> 区域找到 <strong>Source</strong> 下拉框</li><li>选择 <strong>GitHub Actions</strong>（不要选 Deploy from a branch）</li></ol><h3 id="第-2-步-允许-master-分支部署" tabindex="-1">第 2 步：允许 <code>master</code> 分支部署 <a class="header-anchor" href="#第-2-步-允许-master-分支部署" aria-label="Permalink to &quot;第 2 步：允许 \`master\` 分支部署&quot;">​</a></h3><p>首次从 <code>main</code> 切到 <code>master</code> 时，deploy 可能报错：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch &quot;master&quot; is not allowed to deploy to github-pages due to environment protection rules.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>按下面改一次即可：</p><ol><li>打开对应仓库的 Settings → Environments</li><li>点击 <strong>github-pages</strong></li><li>找到 <strong>Deployment branches</strong>（部署分支）</li><li>选 <strong>All branches</strong>，或在 <strong>Selected branches</strong> 里添加 <strong>master</strong></li><li>保存</li></ol><h3 id="第-3-步-重新运行部署" tabindex="-1">第 3 步：重新运行部署 <a class="header-anchor" href="#第-3-步-重新运行部署" aria-label="Permalink to &quot;第 3 步：重新运行部署&quot;">​</a></h3><ol><li>打开仓库 Actions 页面</li><li>点击 <strong>Run workflow</strong> → 选 <code>master</code> → <strong>Run workflow</strong></li><li>等约 1～2 分钟，<strong>build</strong> 和 <strong>deploy</strong> 都变绿 ✓</li></ol><h3 id="第-4-步-确认站点" tabindex="-1">第 4 步：确认站点 <a class="header-anchor" href="#第-4-步-确认站点" aria-label="Permalink to &quot;第 4 步：确认站点&quot;">​</a></h3><p>回到 <strong>Settings → Pages</strong>，顶部应出现：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Your site is live at https://xiaobawang001.github.io/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="若-deploy-仍失败" tabindex="-1">若 deploy 仍失败 <a class="header-anchor" href="#若-deploy-仍失败" aria-label="Permalink to &quot;若 deploy 仍失败&quot;">​</a></h2><table tabindex="0"><thead><tr><th>错误信息</th><th>处理</th></tr></thead><tbody><tr><td><code>Branch &quot;master&quot; is not allowed to deploy...</code></td><td>见上文第 2 步，放行 <code>master</code></td></tr><tr><td><code>Ensure GitHub Pages has been enabled</code></td><td>第 1 步 Source 还没改成 <strong>GitHub Actions</strong></td></tr></tbody></table><hr><h2 id="日常更新" tabindex="-1">日常更新 <a class="header-anchor" href="#日常更新" aria-label="Permalink to &quot;日常更新&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;docs: 更新笔记&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> master</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>推送后 Actions 会自动重新部署。</p><h2 id="本地预览" tabindex="-1">本地预览 <a class="header-anchor" href="#本地预览" aria-label="Permalink to &quot;本地预览&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># http://localhost:5173/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="ssh" tabindex="-1">SSH <a class="header-anchor" href="#ssh" aria-label="Permalink to &quot;SSH&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,30)])])}const u=s(n,[["render",l]]);export{b as __pageData,u as default};
